INSERT INTO `listings` (`id`, `user_id`, `admin_id`, `category_id`, `sub_category_id`, `child_category_id`, `brand_id`, `country_id`, `state_id`, `city_id`, `title`, `slug`, `description`, `qualification`, `experience`, `image`, `gallery_images`, `video_url`, `price`, `expected_salary`, `job_location`, `negotiable`, `condition`, `authenticity`, `phone`, `phone_hidden`, `address`, `lat`, `lon`, `is_featured`, `view`, `status`, `is_published`, `location`, `published_at`, `deleted_at`, `created_at`, `updated_at`) VALUES
	(1, 1, NULL, 50, NULL, NULL, 3, NULL, NULL, NULL, 'Logitech E19 Computer Keyboard for sell', 'logitech-e19-computer-keyboard-for-sell', '<p></p><div style="margin: 0px 28.7969px 0px 14.3906px; padding: 0px; width: 436.797px; text-align: left; float: right; color: rgb(0, 0, 0); font-family: &quot;Open Sans&quot;, Arial, sans-serif; font-size: 14px; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; font-weight: 400; letter-spacing: normal; orphans: 2; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; background-color: rgb(255, 255, 255); text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;"></div><p></p><div style="text-align: justify;"><span style="color: rgb(102, 112, 133); font-family: &quot;Source Sans Pro&quot;, sans-serif; text-align: start;">Direct repair of aneurysm, pseudoaneurysm, or excision (partial or total) and graft insertion, with or without patch graft; for aneurysm, pseudoaneurysm, and associated occlusive disease, abdominal aorta involving iliac vessels (common, hypogastric, external)</span><br></div>', NULL, NULL, '981', '690|689', NULL, 500, NULL, NULL, 1, 'new', 'refurbished', '+8801799328264', 1, 'Dhaka, Bangladesh', 90.3469270, 23.8122516, 0, 767, 1, 1, NULL, '2025-03-18 23:38:01', NULL, '2024-04-24 06:30:12', '2025-03-18 23:38:01'),
	(2, 1, NULL, 50, NULL, NULL, 3, NULL, NULL, NULL, 'Ginior G+ Mouse for Sell at reasonable price', 'ginior-g-mouse-for-sell-at-reasonable-price', '<p><span style="font-family: &quot;Source Sans Pro&quot;, sans-serif;">Direct repair of aneurysm, pseudoaneurysm, or excision (partial or total) and graft insertion, with or without patch graft; for aneurysm, pseudoaneurysm, and associated occlusive disease, abdominal aorta involving iliac vessels (common, hypogastric, external)</span><br></p>', NULL, NULL, '979', '687|688', NULL, 499, NULL, NULL, 1, 'used', 'original', '+8801784677515', 0, 'Dhaka, Bangladesh', 23.8758547, 90.3795438, 0, 1270, 1, 1, NULL, '2025-03-18 23:38:00', NULL, '2024-04-24 07:27:11', '2025-03-18 23:38:00'),
	(3, 1, NULL, 51, NULL, NULL, 3, NULL, NULL, NULL, 'Original Chanel Perfume for Sell', 'original-chanel-perfume-for-sell', '<p><span style="font-family: &quot;Source Sans Pro&quot;, sans-serif;">Direct repair of aneurysm, pseudoaneurysm, or excision (partial or total) and graft insertion, with or without patch graft; for aneurysm, pseudoaneurysm, and associated occlusive disease, abdominal aorta involving iliac vessels (common, hypogastric, external)</span><br></p>', NULL, NULL, '978', '686', NULL, 434, NULL, NULL, 0, 'new', 'refurbished', '+8801799328264', 0, 'Dhaka, Bangladesh', 23.7820624, 90.4160527, 0, 365, 1, 1, NULL, '2025-03-18 23:37:57', NULL, '2024-04-24 23:07:10', '2025-03-18 23:37:57'),
	(4, 1, NULL, 51, NULL, NULL, 4, NULL, NULL, NULL, 'Formal White T-Shirt for Office and Business Party', 'formal-white-t-shirt-for-office-and-business-party', '<p>Elevate your professional look with this Formal White T-Shirt, perfect for both office wear and business parties. Crafted with premium cotton fabric, it offers comfort and breathability throughout the day. Its crisp white hue exudes sophistication and versatility, effortlessly pairing with suits or casual trousers. Designed with a tailored fit, it ensures a polished silhouette, making a lasting impression in any setting. Embrace timeless elegance and refined style with this essential wardrobe staple<br></p>', NULL, NULL, '977', '678|680', NULL, 959, NULL, NULL, 0, 'used', 'original', '+8801799328264', 0, 'Dhaka, Bangladesh', 23.7936706, 90.4066082, 0, 1094, 1, 1, NULL, '2025-03-18 23:37:55', NULL, '2024-04-24 23:33:36', '2025-03-23 12:21:10'),
