	(49, 1, NULL, 3, 12, NULL, NULL, NULL, NULL, NULL, '10 Sustainable Sofa Upcycling', '10-sustainable-sofa-upcycling', 'Discover the art of sofa upcycling with our innovative guide. Transform your old couch into something spectacular with these five simple steps. From reupholstering to repurposing, unleash your creativity and breathe new life into your living space. Say goodbye to waste and hello to sustainable style as you embark on this eco-friendly journey. Elevate your home décor while reducing your environmental footprint – it\'s time to reimagine your sofa!', NULL, NULL, '675', '677|676', NULL, 1000, NULL, NULL, 0, 'new', 'original', '+12013514000', 0, 'Sanger, United States', 36.7782610, -119.4179324, 0, 168, 1, 1, NULL, '2024-06-11 03:12:03', '2025-03-18 23:37:18', '2024-05-30 05:56:57', '2025-03-18 23:37:18'),
	(70, 1, NULL, 9, 29, NULL, 1, NULL, NULL, NULL, 'Apple Latest Headphones', 'apple-latest-headphones', '<p>Apple\'s latest headphones deliver unparalleled audio performance with rich, immersive sound. Equipped with advanced drivers and adaptive EQ, they ensure every note is clear and precise.<br></p>', NULL, NULL, '699', '701|700', NULL, 500, NULL, NULL, 0, 'new', 'original', '+8801799328264', 0, 'Dhaka, Bangladesh', 23.7956037, 90.3536548, 0, 253, 1, 1, NULL, '2024-06-11 03:12:03', '2025-03-18 23:37:12', '2024-06-10 15:36:51', '2025-03-18 23:37:12'),
	(71, 1, NULL, 9, 30, NULL, 3, NULL, NULL, NULL, 'Samsung Galaxy A50', 'samsung-galaxy-a50', '<p><strong>Powerful Performance</strong>: Experience lightning-fast speeds with the latest Snapdragon processor, ideal for multitasking and gaming.</p><p><strong>Stunning Display</strong>: Enjoy vibrant visuals on a 6.7-inch AMOLED screen with a smooth 120Hz refresh rate.</p><p><strong>Pro-Grade Camera</strong>: Capture every moment with a quad-camera system featuring a 108MP main sensor for incredible detail and clarity.</p><p><strong>Long-Lasting Battery</strong>: Stay powered all day with a 5000mAh battery and fast charging capabilities.</p><p><strong>Advanced Connectivity</strong>: Benefit from 5G and Wi-Fi 6 support for seamless and rapid connectivity.</p><p>Don\'t miss out on the Samsung Galaxy S50 – your ultimate smartphone upgrade!</p>', NULL, NULL, '703', '705|704|702', NULL, 2500, NULL, NULL, 1, NULL, 'original', '+41791235784', 0, 'Ridgeland, United States', 32.4276903, -81.0087199, 1, 1, 1, 1, NULL, NULL, '2024-06-11 08:27:20', '2024-06-10 16:07:57', '2024-06-11 08:27:20'),
	(116, 24, NULL, 51, 99, 58, 7, NULL, NULL, NULL, 'Car', 'car', '<p>Car<span style="color: var(--paragraph-color); font-family: var(--body-font1);">A </span><strong data-start="2" data-end="9" style="color: var(--paragraph-color); font-family: var(--body-font1);">car</strong><span style="color: var(--paragraph-color); font-family: var(--body-font1);"> is a four-wheeled motor vehicle designed for transporting passengers. It is one of the most common modes of transportation, available in various types such as sedans, SUVs, hatchbacks, coupes, and sports cars. Cars are powered by internal combustion engines using gasoline or diesel, while modern advancements have introduced electric and hybrid vehicles for eco-friendly alternatives.</span></p>\r\n<p data-start="399" data-end="681">Cars offer convenience, speed, and comfort, making daily commuting and long-distance travel easier. Features such as air conditioning, GPS navigation, infotainment systems, and advanced safety technologies like airbags, ABS, and collision detection enhance the driving experience.</p>\r\n<p data-start="683" data-end="1045" data-is-last-node="" data-is-only-node="">The automotive industry continues to evolve with innovations in autonomous driving, fuel efficiency, and smart connectivity. Cars are not just a means of transport but a symbol of freedom, luxury, and technological progress. From personal use to commercial applications, they play a crucial role in modern society, shaping economies and lifestyles worldwide.&nbsp;</p>', NULL, NULL, '985', NULL, NULL, 1000, NULL, NULL, 0, 'new', 'original', NULL, 0, 'Coimbatore, Tamil Nadu, India', NULL, NULL, 1, 14, 1, 1, NULL, '2025-03-18 23:54:17', NULL, '2025-03-14 05:26:43', '2025-03-20 14:08:03'),
	(117, 24, NULL, 51, 99, 57, 12, NULL, NULL, NULL, 'Bike', 'bike', '<p data-start="0" data-end="397">A <strong data-start="2" data-end="9">car</strong> is a four-wheeled motor vehicle designed for transporting passengers. It is one of the most common modes of transportation, available in various types such as sedans, SUVs, hatchbacks, coupes, and sports cars. Cars are powered by internal combustion engines using gasoline or diesel, while modern advancements have introduced electric and hybrid vehicles for eco-friendly alternatives.</p><p data-start="399" data-end="681">Cars offer convenience, speed, and comfort, making daily commuting and long-distance travel easier. Features such as air conditioning, GPS navigation, infotainment systems, and advanced safety technologies like airbags, ABS, and collision detection enhance the driving experience.</p><p>\r\n\r\n</p><p data-start="683" data-end="1045" data-is-last-node="" data-is-only-node="">The automotive industry continues to evolve with innovations in autonomous driving, fuel efficiency, and smart connectivity. Cars are not just a means of transport but a symbol of freedom, luxury, and technological progress. From personal use to commercial applications, they play a crucial role in modern society, shaping economies and lifestyles worldwide.&nbsp;</p>', NULL, NULL, '989', NULL, NULL, 1000, NULL, NULL, 0, 'new', 'original', '098989898', 0, 'Pappireddipatti, India', 11.0168445, 76.9558321, 0, 18, 1, 1, NULL, '2025-03-18 23:54:17', NULL, '2025-03-14 05:57:27', '2025-03-18 23:54:17'),
	(119, 25, NULL, 54, 107, NULL, NULL, NULL, NULL, NULL, 'Designer', 'designer', '<p data-start="0" data-end="545">A <strong data-start="2" data-end="15">developer</strong> is a technology professional responsible for designing, building, and maintaining software applications, websites, or systems. They specialize in various fields such as <strong data-start="185" data-end="209">frontend development</strong> (creating user interfaces), <strong data-start="238" data-end="261">backend development</strong> (managing databases and server-side logic), or <strong data-start="309" data-end="335">full-stack development</strong> (handling both frontend and backend). Developers use programming languages like JavaScript, Python, PHP, and frameworks such as React, Laravel, or Node.js to create functional and user-friendly applications.</p><p data-start="547" data-end="810">Beyond coding, developers collaborate with designers, product managers, and clients to understand project requirements and ensure seamless functionality. They also debug issues, optimize performance, and implement security measures to maintain software quality.</p><p>\r\n\r\n</p><p data-start="812" data-end="1115" data-is-last-node="" data-is-only-node="">A great developer stays updated with the latest industry trends, embraces problem-solving, and continuously improves their skills. Whether working independently or in a team, they play a crucial role in bringing digital products to life, enhancing user experiences, and driving technological innovation.</p>', 'B.sc', '2', '990', NULL, NULL, 1, 20000.00, 'Chennai', 0, NULL, NULL, '+919870987090', 0, 'Pappireddipatti, India', 11.0168445, 76.9558321, 0, 47, 1, 1, NULL, '2025-03-19 00:26:06', NULL, '2025-03-17 05:42:57', '2025-03-23 12:21:02');
