INSERT INTO `pages` (`id`, `title`, `slug`, `page_content`, `page_class`, `layout`, `sidebar_layout`, `breadcrumb_status`, `navbar_variant`, `footer_variant`, `widget_style`, `left_column`, `right_column`, `visibility`, `back_to_top`, `page_builder_status`, `status`, `created_at`, `updated_at`) VALUES
	(2, 'Contact', 'contact', '<h2 class="tittle p-0" style="margin-bottom: 18px; line-height: 1.4; font-size: 36px; font-family: var(--heading-font); padding-left: 12px; display: inline-block; position: relative;"><b>Get in touch</b></h2><p><span style="color: rgb(102, 112, 133); font-family: &quot;Source Sans Pro&quot;, sans-serif; display: inline !important;"></span></p><p style="color: rgb(102, 112, 133); font-family: &quot;Source Sans Pro&quot;, sans-serif; line-height: 1.6;">Our friendly team would love to hear from you.</p>', NULL, 'normal_layout', NULL, 'on', '01', '01', NULL, NULL, NULL, 'all', NULL, 'on', 'publish', '2024-01-30 00:15:39', '2024-06-27 10:34:50'),
	(3, 'Home One', 'home-one', NULL, NULL, 'home_page_layout', NULL, NULL, '01', '01', NULL, NULL, NULL, 'all', NULL, 'on', 'publish', '2024-01-30 00:16:57', '2024-06-05 05:37:11'),
	(5, 'Terms  and Conditions', 'terms-and-conditions', '<div><font color="#667085" face="Source Sans Pro, sans-serif"><span style="font-size: 16px;"><br></span></font></div>', NULL, 'normal_layout', NULL, 'on', '01', '01', NULL, NULL, NULL, 'all', NULL, 'on', 'publish', '2024-01-30 00:45:39', '2024-06-27 10:34:12'),
	(6, 'Privacy Policy', 'privacy-policy', '<h1 style="padding: 0px; font-family: Roboto, sans-serif; line-height: 1.08333; color: rgb(102, 102, 102); font-size: 48px; outline-style: initial; outline-width: 0px;"><span style="font-size: 18px;"><b><br></b></span></h1><h1 style="padding: 0px; font-family: Roboto, sans-serif; line-height: 1.08333; color: rgb(102, 102, 102); font-size: 48px; outline-style: initial; outline-width: 0px;"><span style="font-size: 18px;"><b><br></b></span></h1><h1 style="padding: 0px; font-family: Roboto, sans-serif; line-height: 1.08333; color: rgb(102, 102, 102); font-size: 48px; outline-style: initial; outline-width: 0px;"><span style="font-size: 18px;"><b>How can I get a privacy policy on my website? A GDPR compliant privacy policy</b></span></h1><p style="margin-right: 0px; margin-left: 0px; padding: 0px; font-family: Roboto, sans-serif; line-height: 1.6; color: rgb(102, 102, 102); outline-style: initial; outline-width: 0px;"><br style="margin: 0px; padding: 0px; outline-style: initial; outline-width: 0px;"></p><p style="margin-right: 0px; margin-left: 0px; padding: 0px; font-family: Gotham, sans-serif; line-height: 1.6; color: rgb(22, 34, 42); outline-style: initial; outline-width: 0px;">The privacy policy can be written as an independent page on your website, and be made accessible as a link in the header or footer of your website, or on your ‘About’ page. It may also be hosted by a privacy policy-service with a link from your homepage. Basically, it doesn’t matter where you choose to place it, as long as your users have access to it. The privacy policy is a legal text. The phrasing depends on which jurisdictions your website falls under and how&nbsp; website handles data.</p><p style="margin-right: 0px; margin-left: 0px; padding: 0px; font-family: Gotham, sans-serif; line-height: 1.6; color: rgb(22, 34, 42); outline-style: initial; outline-width: 0px;"><br style="margin: 0px; padding: 0px; outline-style: initial; outline-width: 0px;"></p><h1 style="padding: 0px; font-family: Gotham, sans-serif; line-height: 1.08333; color: rgb(22, 34, 42); font-size: 16px; outline-style: initial; outline-width: 0px;"><span style="margin: 0px; padding: 0px; outline-style: initial; outline-width: 0px; font-weight: bolder;">All websites are different. We always recommend that you consult a lawyer to ensure that your privacy policy is compliant with all applicable laws.&nbsp;</span></h1><h1 style="padding: 0px; font-family: Gotham, sans-serif; line-height: 1.08333; color: rgb(22, 34, 42); font-size: 16px; outline-style: initial; outline-width: 0px;"><span style="margin: 0px; padding: 0px; outline-style: initial; outline-width: 0px; font-weight: bolder;"><br style="margin: 0px; padding: 0px; outline-style: initial; outline-width: 0px;"></span></h1><h1 style="padding: 0px; font-family: Gotham, sans-serif; line-height: 1.08333; color: rgb(22, 34, 42); font-size: 16px; outline-style: initial; outline-width: 0px;"><span style="margin: 0px; padding: 0px; outline-style: initial; outline-width: 0px; font-weight: bolder;"><br style="margin: 0px; padding: 0px; outline-style: initial; outline-width: 0px;"></span>However, this might seem as a large expense if you are, for instance, a hobby blogger or small business. What you should&nbsp;<a href="https://medium.com/@StartupPolicy/five-reasons-why-copying-someone-else-s-terms-of-use-and-privacy-policy-is-a-bad-idea-fd8d126ac0b3" style="margin: 0px; padding: 0px; color: inherit; text-decoration: none; background-color: rgb(255, 255, 255); transition-duration: 0.3s; transition-timing-function: ease-in-out; transition-property: all; outline-style: initial; outline-width: 0px; font-family: Poppins, sans-serif;">never do, is to copy a privacy policy from some other website</a>.</h1><p style="margin-right: 0px; margin-left: 0px; padding: 0px; font-family: Gotham, sans-serif; line-height: 1.6; color: rgb(22, 34, 42); outline-style: initial; outline-width: 0px;">That is also why using a privacy policy generator can be a hazardous thing, since you must be very careful to include all the specific information of your website, and not just have privacy policy generator spit out a default one that isn\'t aligned with your domain</p><p style="margin-right: 0px; margin-left: 0px; padding: 0px; font-family: Gotham, sans-serif; line-height: 1.6; color: rgb(22, 34, 42); outline-style: initial; outline-width: 0px;"><br style="margin: 0px; padding: 0px; outline-style: initial; outline-width: 0px;"></p><h5 style="padding: 0px; font-family: Roboto, sans-serif; line-height: 1.08333; color: rgb(102, 102, 102); font-size: 16px; outline-style: initial; outline-width: 0px;">GDPR&nbsp;<span style="margin: 0px; padding: 0px; outline-style: initial; outline-width: 0px; font-weight: bolder;">privacy policy templates &amp; privacy policy generators</span></h5><p style="margin-right: 0px; margin-left: 0px; padding: 0px; font-family: Gotham, sans-serif; line-height: 1.6; color: rgb(22, 34, 42); outline-style: initial; outline-width: 0px;">There exists numerous tools for creating privacy policies, and privacy policy templates and privacy policy generators on the internet.</p><p style="margin-right: 0px; margin-left: 0px; padding: 0px; font-family: Gotham, sans-serif; line-height: 1.6; color: rgb(22, 34, 42); outline-style: initial; outline-width: 0px;">Some are free and others come at a price. Some are not GDPR compliant privacy policies.</p><p style="margin-right: 0px; margin-left: 0px; padding: 0px; font-family: Gotham, sans-serif; line-height: 1.6; color: rgb(22, 34, 42); outline-style: initial; outline-width: 0px;"><br style="margin: 0px; padding: 0px; outline-style: initial; outline-width: 0px;"></p><p style="margin-right: 0px; margin-left: 0px; padding: 0px; font-family: Gotham, sans-serif; line-height: 1.6; color: rgb(22, 34, 42); outline-style: initial; outline-width: 0px;">1) Maintain all the content properly</p><p style="margin-right: 0px; margin-left: 0px; padding: 0px; font-family: Gotham, sans-serif; line-height: 1.6; color: rgb(22, 34, 42); outline-style: initial; outline-width: 0px;">2) Ensure your all input is right</p><p style="margin-right: 0px; margin-left: 0px; padding: 0px; font-family: Gotham, sans-serif; line-height: 1.6; color: rgb(22, 34, 42); outline-style: initial; outline-width: 0px;">3) if you can do multiple task that will be plus</p><p style="margin-right: 0px; margin-left: 0px; padding: 0px; font-family: Gotham, sans-serif; line-height: 1.6; color: rgb(22, 34, 42); outline-style: initial; outline-width: 0px;"><br style="margin: 0px; padding: 0px; outline-style: initial; outline-width: 0px;"></p><p style="margin-right: 0px; margin-left: 0px; padding: 0px; font-family: Gotham, sans-serif; line-height: 1.6; color: rgb(22, 34, 42); outline-style: initial; outline-width: 0px;">There policy is the numerous tools for creating privacy policies, and privacy policy templates and privacy policy generators on the internet. Some are free and others come at a price. Some are not GDPR compliant privacy policies.</p><p style="margin-right: 0px; margin-left: 0px; padding: 0px; font-family: Gotham, sans-serif; line-height: 1.6; color: rgb(22, 34, 42); outline-style: initial; outline-width: 0px;"><br style="margin: 0px; padding: 0px; outline-style: initial; outline-width: 0px;"></p><p style="margin-right: 0px; margin-left: 0px; padding: 0px; font-family: Gotham, sans-serif; line-height: 1.6; color: rgb(22, 34, 42); outline-style: initial; outline-width: 0px;"><span style="margin: 0px; padding: 0px; outline-style: initial; outline-width: 0px; font-weight: bolder;">Note :&nbsp;</span>just have privacy policy generator spit out a default one that isn\'t aligned with your domain So it\'s very important loyal technical theury of our reservation.</p><p style="margin-right: 0px; margin-left: 0px; padding: 0px; font-family: Gotham, sans-serif; line-height: 1.6; color: rgb(22, 34, 42); outline-style: initial; outline-width: 0px;"><br></p><p style="margin-right: 0px; margin-left: 0px; padding: 0px; font-family: Gotham, sans-serif; line-height: 1.6; color: rgb(22, 34, 42); outline-style: initial; outline-width: 0px;"><br></p><p style="margin-right: 0px; margin-left: 0px; padding: 0px; font-family: Gotham, sans-serif; line-height: 1.6; color: rgb(22, 34, 42); outline-style: initial; outline-width: 0px;"><br></p><p style="margin-right: 0px; margin-left: 0px; padding: 0px; font-family: Gotham, sans-serif; line-height: 1.6; color: rgb(22, 34, 42); outline-style: initial; outline-width: 0px;"><br></p>', NULL, 'normal_layout', NULL, 'on', '01', '01', NULL, NULL, NULL, 'all', NULL, NULL, 'publish', '2024-01-30 00:45:56', '2024-06-27 10:34:15'),
	(7, 'Faq', 'faq', NULL, NULL, 'normal_layout', NULL, 'on', '01', '01', NULL, NULL, NULL, 'all', NULL, 'on', 'publish', '2024-01-30 00:46:28', '2024-06-27 10:34:20'),
	(8, 'Safety Informations', 'safety-informations', '<p><strong><br></strong></p><p><strong><br></strong></p><p><strong><br></strong></p><p><strong>Safety Information</strong></p>\r\n<p>At Listocean, your safety and security are our top priorities. We want to ensure that you have a safe and enjoyable experience while using our website. Please take a moment to review the following safety tips and guidelines:</p><p><br></p>\r\n<ol>\r\n<li>\r\n<p><strong>Protect Your Personal Information:</strong></p>\r\n<ul>\r\n<li>Be cautious when sharing personal information online, such as your full name, address, phone number, or financial details.</li>\r\n<li>Avoid posting sensitive information publicly on the website, including in comments, reviews, or forum discussions.</li>\r\n<li>Use strong and unique passwords for your account and avoid sharing them with others.</li></ul></li></ol><ol>\r\n<li>\r\n<p><strong>Beware of Scams and Fraud:</strong></p>\r\n<ul>\r\n<li>Be wary of offers that seem too good to be true, especially those requesting payment or personal information upfront.</li>\r\n<li>Do not respond to unsolicited emails, messages, or requests for money or personal information.</li>\r\n<li>If something seems suspicious or fraudulent, report it to us immediately so we can investigate.</li></ul></li></ol><ol>\r\n<li>\r\n<p><strong>Use Secure Payment Methods:</strong></p>\r\n<ul>\r\n<li>Only make payments through secure and trusted payment gateways provided on our website.</li>\r\n<li>Verify the legitimacy of sellers and listings before making a purchase, especially for high-value items.</li></ul></li></ol><ol>\r\n<li>\r\n<p><strong>Stay Vigilant Against Phishing Attacks:</strong></p>\r\n<ul>\r\n<li>Be cautious of emails or messages that ask you to click on suspicious links or provide sensitive information.</li>\r\n<li>Look for signs of phishing, such as misspelled email addresses, unfamiliar senders, and urgent requests for personal information.</li>\r\n<li>If in doubt, contact us directly through our official channels to verify the authenticity of the communication.</li></ul></li></ol><ol>\r\n<li>\r\n<p><strong>Practice Safe Online Interactions:</strong></p>\r\n<ul>\r\n<li>Use caution when communicating with strangers online, especially in private messages or chat rooms.</li>\r\n<li>Report any inappropriate or abusive behavior to us immediately, and block the user if necessary.</li>\r\n<li>Trust your instincts and avoid engaging in risky or potentially dangerous situations.</li></ul></li></ol><ol>\r\n<li>\r\n<p><strong>Protect Your Devices and Accounts:</strong></p>\r\n<ul>\r\n<li>Keep your devices, operating systems, and antivirus software up to date with the latest security patches.</li>\r\n<li>Enable two-factor authentication (2FA) for an extra layer of security on your accounts.</li>\r\n<li>Be cautious of public Wi-Fi networks and use a virtual private network (VPN) when accessing sensitive information online.</li></ul></li></ol><ol>\r\n<li>\r\n<p><strong>Report Safety Concerns:</strong></p>\r\n<ul>\r\n<li>If you encounter any safety issues, suspicious activity, or violations of our community guidelines, please report them to us immediately.</li>\r\n<li>Your feedback helps us maintain a safe and secure environment for all users.</li></ul></li></ol>\r\n<p>Remember, your safety is our priority, but ultimately, you are responsible for your own safety and security while using our website. By following these safety tips and guidelines, you can help protect yourself and others from potential risks and dangers online.</p>\r\n<p>If you have any questions or concerns about safety on our website, please don\'t hesitate to contact us. Thank you for being a valued member of our community!</p><p><br></p><p><br></p><p><br></p><p><br></p>', NULL, 'normal_layout', NULL, 'on', '01', '01', NULL, NULL, NULL, 'all', NULL, NULL, 'publish', '2024-01-30 00:46:35', '2024-06-27 10:34:23'),
	(13, 'Test Page', 'test-page', '<p><div style="margin: 0px 28.7969px 0px 14.3906px; padding: 0px; width: 436.797px; text-align: left; float: right; color: rgb(0, 0, 0); font-family: &quot;Open Sans&quot;, Arial, sans-serif; font-size: 14px; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; font-weight: 400; letter-spacing: normal; orphans: 2; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; background-color: rgb(255, 255, 255); text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;"></div></p><div style="text-align: justify;"><span style="text-align: var(--bs-body-text-align); display: inline !important; font-size: 16px;"><font face="Open Sans, Arial, sans-serif"><b>Lorem Ipsum is simply dummy text of the printing and typesetting industry. Lorem Ipsum has been the industry\'s standard dummy text ever since the 1500s, when an unknown printer took a galley of type and scrambled it to make a type specimen book. It has survived not only five centuries, but also the leap into electronic typesetting, remaining essentially unchanged. It was popularised in the 1960s with the release of Letraset sheets containing Lorem Ipsum passages, and more recently with desktop publishing software like Aldus PageMaker including versions of Lorem Ipsum</b></font></span></div><div style="text-align: justify;"><span style="text-align: var(--bs-body-text-align); display: inline !important; font-size: 16px;"><font face="Open Sans, Arial, sans-serif"><b><br></b></font></span></div><div style="margin: 0px 28.7969px 0px 14.3906px; padding: 0px; width: 436.797px; float: right; color: rgb(0, 0, 0); font-family: &quot;Open Sans&quot;, Arial, sans-serif;"></div>', NULL, 'normal_layout', NULL, 'on', '01', '01', NULL, NULL, NULL, 'all', NULL, 'on', 'draft', '2024-01-30 01:58:40', '2024-06-05 05:36:49'),
