	(231, 'safety_tips_info', '<ol><li style="display: flex; align-items: center; gap: 8px; color: rgb(15, 23, 42); font-family: Inter, sans-serif; font-size: 16px; background-color: rgb(255, 247, 237); line-height: 1.5;"><img src="data:image/png;base64," data-filename="Vector.png" style="font-weight: var(--bs-body-font-weight); text-align: var(--bs-body-text-align); width: 16px; height: 16px;"><span style="font-weight: var(--bs-body-font-weight); text-align: var(--bs-body-text-align);"><span style="font-weight: var(--bs-body-font-weight); text-align: var(--bs-body-text-align);">Meet in a public place.</span></span></li><li style="display: flex; align-items: center; gap: 8px; color: rgb(15, 23, 42); font-family: Inter, sans-serif; font-size: 16px; background-color: rgb(255, 247, 237); line-height: 1.5;"><span style="font-weight: var(--bs-body-font-weight); text-align: var(--bs-body-text-align); display: inline !important;"><ol style="margin-bottom: 1rem; color: rgb(102, 102, 102); font-family: sans-serif; font-size: 14px;"><li style="display: flex; align-items: center; gap: 8px; color: rgb(15, 23, 42); font-family: Inter, sans-serif; font-size: 16px; line-height: 1.5;"><span style="font-weight: var(--bs-body-font-weight); text-align: var(--bs-body-text-align);"><img src="data:image/png;base64," data-filename="Vector.png" style="width: 16px; height: 16px;">&nbsp;&nbsp;<span style="font-weight: var(--bs-body-font-weight); text-align: var(--bs-body-text-align);">Don’t pay in advance.</span></span></li><li style="display: flex; align-items: center; gap: 8px; color: rgb(15, 23, 42); font-family: Inter, sans-serif; font-size: 16px; line-height: 1.5;"><img src="data:image/png;base64," data-filename="Vector.png" style="width: 16px; height: 16px;"><span style="font-weight: var(--bs-body-font-weight); text-align: var(--bs-body-text-align);">Verify item condition.</span></li><li style="display: flex; align-items: center; gap: 8px; color: rgb(15, 23, 42); font-family: Inter, sans-